     5→use App\Models\ActivityLog;
     6→use App\Models\Project;
     7→use App\Models\Task;
     8→use Illuminate\Http\JsonResponse;
     9→
    10→class ActivityLogController extends Controller
    11→{
    12→    public function forProject(Project $project): JsonResponse
    13→    {
    14→        $this->authorize('view', $project);
    15→
    16→        $logs = ActivityLog::with('user')
    17→            ->forLoggable(Project::class, $project->id)
    18→            ->latest('created_at')
    19→            ->limit(50)
    20→            ->get()
    21→            ->map(fn ($log) => $this->formatLog($log));
    22→
    23→        return response()->json($logs);
    24→    }
    25→
    26→    public function forTask(Task $task): JsonResponse
    27→    {
    28→        $this->authorize('update', $task);
    29→
    30→        $logs = ActivityLog::with('user')
    31→            ->forLoggable(Task::class, $task->id)
    32→            ->latest('created_at')
    33→            ->limit(50)
    34→            ->get()
    35→            ->map(fn ($log) => $this->formatLog($log));
    36→
    37→        return response()->json($logs);
    38→    }
    39→
    40→    private function formatLog(ActivityLog $log): array
    41→    {
    42→        return [
    43→            'id'         => $log->id,
    44→            'event'      => $log->event,
    45→            'old_values' => $log->old_values,
    46→            'new_values' => $log->new_values,
    47→            'created_at' => $log->created_at->format('d/m/Y H:i'),
    48→            'user'       => $log->user?->name ?? 'Sistema',
    49→        ];
    50→    }
    51→}
