    10→describe('LogsActivity trait', function () {
    11→
    12→    beforeEach(function () {
    13→        $this->user = User::factory()->create();
    14→        $this->actingAs($this->user);
    15→    });
    16→
    17→    it('logs a created event when a project is created', function () {
    18→        $project = Project::factory()->create(['user_id' => $this->user->id]);
    19→
    20→        expect(ActivityLog::count())->toBe(1);
    21→        $log = ActivityLog::first();
    22→        expect($log->event)->toBe('created');
    23→        expect($log->loggable_type)->toBe(Project::class);
    24→        expect($log->loggable_id)->toBe($project->id);
    25→        expect($log->user_id)->toBe($this->user->id);
    26→        expect($log->old_values)->toBeNull();
    27→        expect($log->new_values)->toHaveKey('name');
    28→    });
    29→
    30→    it('logs an updated event when a watched attribute changes on a project', function () {
    31→        $project = Project::factory()->create(['user_id' => $this->user->id, 'name' => 'Old Name']);
    32→        ActivityLog::truncate();
    33→
    34→        $project->update(['name' => 'New Name']);
    35→
    36→        expect(ActivityLog::count())->toBe(1);
    37→        $log = ActivityLog::first();
    38→        expect($log->event)->toBe('updated');
    39→        expect($log->old_values)->toBe(['name' => 'Old Name']);
    40→        expect($log->new_values)->toBe(['name' => 'New Name']);
    41→    });
    42→
    43→    it('does not log when only unwatched attributes change on a task', function () {
    44→        $project = Project::factory()->create(['user_id' => $this->user->id]);
    45→        $task = Task::factory()->create(['project_id' => $project->id]);
    46→        ActivityLog::truncate();
    47→
    48→        $task->update(['position' => 99]);
    49→
    50→        expect(ActivityLog::count())->toBe(0);
    51→    });
    52→
    53→    it('logs a deleted event when a project is deleted', function () {
    54→        $project = Project::factory()->create(['user_id' => $this->user->id]);
    55→        $projectId = $project->id;
    56→        ActivityLog::truncate();
    57→
    58→        $project->delete();
    59→
    60→        expect(ActivityLog::count())->toBe(1);
    61→        $log = ActivityLog::first();
    62→        expect($log->event)->toBe('deleted');
    63→        expect($log->loggable_id)->toBe($projectId);
    64→        expect($log->old_values)->toHaveKey('name');
    65→        expect($log->new_values)->toBeNull();
    66→    });
    67→
    68→    it('does not log when no watched attribute changes', function () {
    69→        $project = Project::factory()->create(['user_id' => $this->user->id]);
    70→        ActivityLog::truncate();
    71→
    72→        // Saving with the same values — getDirty() will be empty
    73→        $project->update(['name' => $project->name]);
    74→
    75→        expect(ActivityLog::count())->toBe(0);
    76→    });
    77→
    78→    it('does not crash when there is no authenticated user (seeder context)', function () {
    79→        auth()->logout();
    80→
    81→        $project = Project::factory()->create(['user_id' => $this->user->id]);
    82→
    83→        // Should log nothing when not authenticated (guard prevents it)
    84→        expect(ActivityLog::count())->toBe(0);
    85→    });
    86→
    87→    it('logs status change when a task status is updated', function () {
    88→        $project = Project::factory()->create(['user_id' => $this->user->id]);
    89→        $task = Task::factory()->create(['project_id' => $project->id, 'status' => 'backlog']);
    90→        ActivityLog::truncate();
    91→
    92→        $task->update(['status' => 'in_progress', 'position' => 0]);
    93→
    94→        expect(ActivityLog::count())->toBe(1);
    95→        $log = ActivityLog::first();
    96→        expect($log->event)->toBe('updated');
    97→        expect($log->new_values)->toBe(['status' => 'in_progress']);
    98→        expect($log->old_values)->toBe(['status' => 'backlog']);
    99→    });
   100→
